window.PEPP_DATA = {"manifest":{"id":"pepp","title":"PEPP — Pediatric Education for Prehospital Professionals","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Based on the AAP PEPP, 4th Edition","description":"A comprehensive, self-contained study reviewer for Pediatric Education for Prehospital Professionals. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, decision trees, high-yield flashcards, PEPP-style quiz questions, and realistic pediatric scenarios. Built around the Pediatric Assessment Triangle, spanning both BLS- and ALS-level prehospital pediatric care, for EMTs, AEMTs, paramedics, and other prehospital providers.","icon":"baby","color":"#2ea043","accentColor":"#e06090","estimatedHours":14,"difficulty":"Beginner to Advanced","certification":"AAP PEPP Provider (BLS or ALS track)","examLink":"https://www.aap.org/en/pedialink/pediatric-education-for-prehospital-professionals/","audience":["EMT","AEMT","Paramedic","EMS Student"],"prerequisites":["Current BLS provider competency","PALS knowledge helpful but not required"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Why Children Are Different: Developmental & Anatomic Considerations","section":"Foundations","difficulty":"Beginner"},{"id":"c02","number":2,"title":"The Pediatric Assessment Triangle","section":"Foundations","difficulty":"Beginner"},{"id":"c03","number":3,"title":"Primary Assessment (ABCDE) & Scene Size-Up","section":"Foundations","difficulty":"Intermediate"},{"id":"c04","number":4,"title":"History Taking, Secondary Assessment & Family-Centered Communication","section":"Foundations","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Respiratory Distress & Respiratory Failure","section":"Respiratory","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Shock Recognition & Field Management","section":"Circulation","difficulty":"Intermediate"},{"id":"c07","number":7,"title":"Cardiac Emergencies & Rhythm Recognition","section":"Circulation","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Neurologic Emergencies: Altered Mental Status & Seizures","section":"Neurologic","difficulty":"Intermediate"},{"id":"c09","number":9,"title":"Trauma: Assessment & Field Stabilization","section":"Trauma","difficulty":"Advanced"},{"id":"c10","number":10,"title":"Toxic Exposures & Environmental Emergencies","section":"Medical","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Neonatal Care & Resuscitation Basics","section":"Neonatal","difficulty":"Advanced"},{"id":"c12","number":12,"title":"Child Maltreatment Recognition","section":"Special Populations","difficulty":"Intermediate"},{"id":"c13","number":13,"title":"Children With Special Healthcare Needs & Technology Dependence","section":"Special Populations","difficulty":"Intermediate"},{"id":"c14","number":14,"title":"EMS Operations: Transport Decisions, Disaster & MCI Triage Involving Children","section":"Operations","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Why Children Are Different: Developmental & Anatomic Considerations","shortTitle":"Why Children Are Different","estimatedStudyTime":26,"difficulty":"Beginner","learningObjectives":["Explain why 'children are not small adults' as an organizing principle of pediatric prehospital care.","Describe key airway anatomic differences between children and adults.","Describe key differences in pediatric breathing mechanics and metabolic demand.","Describe key differences in pediatric circulating blood volume and compensatory capacity.","Relate developmental stage to communication and cooperation during assessment.","Use age-banded normal vital signs as a baseline for recognizing abnormal findings."],"summary":[{"title":"Children Are Not Small Adults","content":"The single organizing idea behind PEPP is that children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size. A treatment or assessment approach scaled down from an adult protocol without accounting for these differences will miss findings or cause harm. This chapter lays the anatomic and developmental groundwork that every later PEPP chapter builds on."},{"title":"Airway: Small, Anterior, and Easily Obstructed","content":"A child's tongue is proportionally larger relative to the oropharynx, the airway is narrower at every level, and the larynx sits more anterior and cephalad (higher in the neck) than in an adult. The narrowest part of the pediatric airway is subglottic (below the vocal cords) in young children, unlike the adult airway, which narrows at the cords. These differences make children more prone to airway obstruction from secretions, a large tongue, or swelling, and require different airway-positioning and equipment-sizing approaches than adult care."},{"title":"Breathing: Higher Demand, Less Reserve","content":"Children have a higher metabolic rate and oxygen consumption per kilogram than adults, but smaller functional residual capacity (oxygen reserve in the lungs). Infants are primarily diaphragmatic breathers with a more compliant (flexible) chest wall, meaning they generate less effective negative pressure and fatigue faster during increased work of breathing. The practical result: children desaturate faster than adults when breathing is compromised, and respiratory problems are the leading pathway to pediatric cardiac arrest."},{"title":"Circulation: Small Volume, Strong Compensation, Then Collapse","content":"A child's absolute circulating blood volume is small, so even modest-seeming blood or fluid losses represent a larger percentage of total volume than the same loss would in an adult. Children compensate remarkably well for volume loss through tachycardia and vasoconstriction, often maintaining a normal blood pressure until a large percentage of volume is lost — meaning blood pressure is a late and unreliable early warning sign in children. When compensation fails, children can decompensate rapidly and with little warning."},{"title":"Developmental Stage Shapes the Encounter","content":"How a child responds to assessment, and how a provider should approach them, changes by developmental stage: infants respond to caregivers' calm presence and are assessed largely by observation; toddlers and preschoolers fear separation from caregivers and unfamiliar equipment, and benefit from keeping the caregiver close and demonstrating equipment on a doll or the caregiver first; school-age children can usually cooperate with direct, honest explanation; adolescents want privacy, respect, and honesty, and may be interviewed partly apart from caregivers. Matching the approach to developmental stage improves both cooperation and the accuracy of the assessment."},{"title":"Why Age-Banded Vital Signs Matter","content":"Because normal heart rate, respiratory rate, and blood pressure change substantially across childhood, a single 'normal vitals' reference is useless in pediatrics. Every vital sign must be interpreted against the age-appropriate normal range (see the table in this chapter), and — critically — trends and the overall clinical picture (the Pediatric Assessment Triangle, covered next chapter) matter more than any single vital sign in isolation."}],"clinicalPearls":["'Children are not small adults' — anatomic, physiologic, developmental, and psychosocial differences change assessment and care at every step.","The pediatric airway's narrowest point is subglottic, below the vocal cords, unlike the adult airway.","Respiratory problems are the leading pathway to pediatric cardiac arrest — protecting breathing protects the whole child.","Blood pressure is a late sign in pediatric shock; children compensate well, then decompensate fast.","Match your approach to developmental stage — a toddler and an adolescent need very different communication styles."],"redFlags":["Using an unmodified adult mental model for airway, breathing, or circulation assessment in a child.","Reassurance from a 'normal' blood pressure in a child with tachycardia and other perfusion concerns.","Approaching a toddler by separating them from a caregiver or leading with unfamiliar equipment."],"commonMistakes":["Treating a single vital sign as normal or abnormal without checking it against the age-appropriate range.","Assuming a calm-appearing infant is not working hard to breathe, when diaphragmatic breathing and chest-wall compliance mask early distress.","Ignoring developmental stage and using the same communication approach for a toddler and a teenager."],"memoryAids":["Children are not small adults — different anatomy, physiology, development, and psychosocial needs.","Pediatric airway = narrow, anterior, subglottic narrowest point.","Compensate hard, then collapse fast — blood pressure lags in pediatric shock.","Match communication to developmental stage, not just to age in years."],"decisionTrees":[{"title":"Applying Age-Appropriate Context to Any Finding","content":"Vital sign or exam finding obtained\n  → Identify the child's age band (see Age-Banded Normal Vital Signs table)\n  → Compare the finding to that age band's normal range — NOT an adult or generic pediatric range\n  → Consider developmental stage for how the assessment itself was obtained (cooperative vs. observed-only)\n  → Weigh the finding within the overall clinical gestalt (Pediatric Assessment Triangle), not in isolation"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Developmental and Anatomic Considerations","courses/pals/data/pals/tables/c01.json — Age-Banded Normal Pediatric Vital Signs (reused exactly)"]},"c02":{"id":"c02","title":"The Pediatric Assessment Triangle","shortTitle":"Pediatric Assessment Triangle","estimatedStudyTime":35,"difficulty":"Beginner","learningObjectives":["Define the Pediatric Assessment Triangle (PAT) and its three legs.","Assess Appearance using observable behavioral characteristics.","Assess Work of Breathing using visual and auditory cues, without a stethoscope.","Assess Circulation to Skin using color and temperature cues.","Use the PAT to form a general impression of 'sick vs. not sick' and likely physiologic category.","Explain why the PAT is performed before, not instead of, hands-on primary assessment."],"summary":[{"title":"What the PAT Is","content":"The Pediatric Assessment Triangle (PAT) is PEPP's signature tool: a rapid, hands-off, across-the-room visual and auditory assessment performed within the first seconds of encountering a child, before you ever touch the patient. It has three legs — Appearance, Work of Breathing, and Circulation to Skin — assessed together to form a general impression of how sick the child is and which body system is likely involved, guiding the pace and priority of everything that follows."},{"title":"Leg 1 — Appearance","content":"Appearance captures the child's overall level of interaction with the environment and is often summarized with the mnemonic TICLS: Tone (moving spontaneously or limp), Interactiveness (alert and engaged, or uninterested), Consolability (can they be comforted, or are they inconsolable), Look/Gaze (do they fix their gaze on you or a caregiver, or stare blankly), and Speech/Cry (strong and appropriate for age, or weak/muffled/absent). Appearance is the single most sensitive PAT leg for detecting adequacy of oxygenation, ventilation, brain perfusion, and CNS function — an abnormal Appearance is a red flag even when the other two legs look normal."},{"title":"Leg 2 — Work of Breathing","content":"Work of Breathing is assessed by listening and looking, without a stethoscope: abnormal airway sounds (stridor, grunting, wheezing, muffled voice), abnormal positioning (tripod position, sniffing position, refusal to lie down), retractions (visible pulling in at the suprasternal, intercostal, or subcostal areas), and nasal flaring or head bobbing. Work of Breathing reflects the child's effort to compensate for an oxygenation or ventilation problem, and increases before oxygen saturation necessarily falls — it is an early window into respiratory status."},{"title":"Leg 3 — Circulation to Skin","content":"Circulation to Skin assesses perfusion by looking at skin and mucous membrane color: pallor (pale, poor perfusion), mottling (patchy discoloration), and cyanosis (bluish, indicating significant hypoxemia), assessed against the child's baseline skin tone in adequate lighting. This leg reflects how well the core is perfusing the periphery and is an early clue to shock, sometimes appearing before other perfusion signs are measurable."},{"title":"Putting the Three Legs Together","content":"No single leg is assessed in isolation — the pattern across all three legs points toward a likely physiologic category. Abnormal Appearance with normal Work of Breathing and Circulation suggests a primarily CNS/metabolic problem. Abnormal Appearance and Work of Breathing with normal Circulation suggests a respiratory problem. Abnormal Appearance and Circulation with normal Work of Breathing suggests a circulatory/shock problem. Abnormal findings across all three legs suggest a severe, multi-system problem (cardiopulmonary failure) requiring the most urgent response. This pattern recognition takes seconds and drives the pace of everything that follows."},{"title":"The PAT Comes First, Not Instead","content":"The PAT is completed before hands-on primary assessment (ABCDE) begins — it sets the general impression and urgency level that shapes how quickly and in what order the primary assessment proceeds, but it does not replace it. A child who looks fine on PAT still gets a full primary assessment; a child who looks critically ill on PAT gets that primary assessment started immediately and rapidly, potentially with simultaneous life-saving interventions. The PAT is the 'from the doorway' first 15 seconds of every pediatric encounter in PEPP."}],"clinicalPearls":["PAT = Appearance + Work of Breathing + Circulation to Skin — hands-off, done from across the room, in the first seconds of contact.","TICLS for Appearance: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Abnormal Appearance alone, even with normal breathing and circulation, is a red flag — it's the most sensitive PAT leg.","The PAT sets your pace; it never replaces the hands-on primary assessment that follows it."],"redFlags":["An inconsolable, limp, or gaze-unfocused child (abnormal Appearance) — treat as high acuity regardless of vital signs not yet obtained.","Retractions, grunting, or head bobbing (abnormal Work of Breathing) — signs of significant respiratory effort, act before full desaturation occurs.","Mottled or cyanotic skin (abnormal Circulation to Skin) — a perfusion problem is already underway."],"commonMistakes":["Reaching for a stethoscope or BP cuff before completing the hands-off PAT.","Treating one PAT leg as the whole picture instead of reading the pattern across all three.","Skipping the primary assessment because the PAT looked reassuring."],"memoryAids":["PAT legs: Appearance, Work of Breathing, Circulation to Skin.","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","1 abnormal leg = CNS/metabolic; 2 legs (Appearance+WOB) = respiratory; 2 legs (Appearance+Circ) = shock; all 3 = cardiopulmonary failure.","PAT is the first 15 seconds — from the doorway, before you touch the child."],"decisionTrees":[{"title":"Pediatric Assessment Triangle Pattern Recognition","content":"From across the room, assess all three legs simultaneously:\n  Appearance (TICLS) | Work of Breathing | Circulation to Skin\n\nPattern → Likely category:\n  Abnormal Appearance ONLY → CNS/metabolic problem\n  Abnormal Appearance + Work of Breathing → Respiratory problem\n  Abnormal Appearance + Circulation → Shock (circulatory problem)\n  Abnormal ALL THREE → Cardiopulmonary failure (highest urgency)\n  All THREE normal → Stable general impression, proceed to routine primary assessment\n\n  → In every case, PAT sets urgency, then proceed to full ABCDE primary assessment"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — The Pediatric Assessment Triangle","courses/pals/data/pals/tables/c01.json — Pediatric Assessment Triangle: Components and Findings (cross-referenced, not duplicated verbatim)"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is the single organizing principle behind PEPP's approach to pediatric care?","answer":"Children are not small adults — they differ anatomically, physiologically, developmentally, and psychosocially, not just in size.","category":"Core Concepts"},{"id":"c01_fc02","question":"Where is the narrowest point of a young child's airway?","answer":"Subglottic (below the vocal cords) — unlike the adult airway, which narrows at the vocal cords.","category":"Airway"},{"id":"c01_fc03","question":"Why is a child's tongue an airway concern?","answer":"It is proportionally larger relative to the oropharynx than an adult's, making obstruction more likely.","category":"Airway"},{"id":"c01_fc04","question":"How does a child's metabolic rate/oxygen consumption compare to an adult's?","answer":"Higher per kilogram, combined with smaller functional residual capacity (oxygen reserve) — children desaturate faster.","category":"Breathing"},{"id":"c01_fc05","question":"What type of breathers are infants primarily?","answer":"Diaphragmatic breathers, with a more compliant (flexible) chest wall than older children/adults.","category":"Breathing"},{"id":"c01_fc06","question":"What is the leading pathway to pediatric cardiac arrest?","answer":"Respiratory problems — unlike adults, where cardiac causes predominate.","category":"Breathing"},{"id":"c01_fc07","question":"Why is blood pressure a late sign of shock in children?","answer":"Children compensate well for volume loss via tachycardia and vasoconstriction, maintaining normal BP until a large percentage of volume is lost.","category":"Circulation"},{"id":"c01_fc08","question":"What happens once a child's compensatory mechanisms for shock fail?","answer":"Rapid decompensation with little warning.","category":"Circulation"},{"id":"c01_fc09","question":"How should you approach a toddler or preschooler during assessment?","answer":"Keep the caregiver close, demonstrate equipment on a doll or the caregiver first, minimize separation anxiety triggers.","category":"Assessment"},{"id":"c01_fc10","question":"How should you approach an adolescent during assessment?","answer":"With privacy, respect, and honesty; consider interviewing partly apart from caregivers.","category":"Assessment"},{"id":"c01_fc11","question":"Why is a single 'normal vitals' reference useless in pediatrics?","answer":"Normal heart rate, respiratory rate, and blood pressure change substantially across childhood age bands.","category":"Assessment"},{"id":"c01_fc12","question":"What matters more than any single vital sign in isolation?","answer":"Trends over time and the overall clinical picture (the Pediatric Assessment Triangle).","category":"Assessment"},{"id":"c01_fc13","question":"Why can a child's absolute blood volume loss seem 'modest' but still be dangerous?","answer":"A child's total circulating blood volume is small, so the same absolute loss represents a larger percentage of total volume than in an adult.","category":"Circulation"},{"id":"c01_fc14","question":"How does the pediatric larynx position differ from an adult's?","answer":"It sits more anterior and cephalad (higher in the neck).","category":"Airway"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"What are the three legs of the Pediatric Assessment Triangle (PAT)?","answer":"Appearance, Work of Breathing, and Circulation to Skin.","category":"PAT"},{"id":"c02_fc02","question":"What does TICLS stand for?","answer":"Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry — the components of Appearance.","category":"PAT"},{"id":"c02_fc03","question":"Why is Appearance the most sensitive PAT leg?","answer":"It reflects adequacy of oxygenation, ventilation, brain perfusion, and CNS function — abnormal Appearance is a red flag even with normal breathing/circulation.","category":"PAT"},{"id":"c02_fc04","question":"How is Work of Breathing assessed?","answer":"By looking and listening without a stethoscope: abnormal sounds, abnormal positioning, retractions, nasal flaring, head bobbing.","category":"PAT"},{"id":"c02_fc05","question":"How is Circulation to Skin assessed?","answer":"By skin/mucous membrane color: pallor, mottling, or cyanosis, compared to the child's baseline in adequate lighting.","category":"PAT"},{"id":"c02_fc06","question":"What does abnormal Appearance alone (normal WOB and Circulation) suggest?","answer":"A primarily CNS/metabolic problem.","category":"PAT"},{"id":"c02_fc07","question":"What does abnormal Appearance + Work of Breathing suggest?","answer":"A respiratory problem.","category":"PAT"},{"id":"c02_fc08","question":"What does abnormal Appearance + Circulation suggest?","answer":"A shock/circulatory problem.","category":"PAT"},{"id":"c02_fc09","question":"What does abnormality across all three PAT legs suggest?","answer":"Cardiopulmonary failure — the most urgent category.","category":"PAT"},{"id":"c02_fc10","question":"When is the PAT performed relative to the primary assessment?","answer":"Before it — the PAT is hands-off and sets the pace/urgency, but does not replace the hands-on primary (ABCDE) assessment that follows.","category":"PAT"},{"id":"c02_fc11","question":"Is the PAT performed with a stethoscope or BP cuff?","answer":"No — it is entirely hands-off, done visually and by listening from across the room.","category":"PAT"},{"id":"c02_fc12","question":"What does 'retractions' mean in the Work of Breathing assessment?","answer":"Visible pulling in of the chest wall at the suprasternal, intercostal, or subcostal areas during breathing effort.","category":"PAT"},{"id":"c02_fc13","question":"Why does Work of Breathing increase before oxygen saturation falls?","answer":"Increased effort reflects the body's compensation for an oxygenation/ventilation problem, occurring before desaturation is measurable.","category":"PAT"},{"id":"c02_fc14","question":"A child looks completely normal on PAT. What should you still do?","answer":"Proceed to a full hands-on primary assessment — a normal PAT does not skip that step, it just sets a calmer pace.","category":"PAT"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What is the core organizing principle of PEPP's approach to pediatric patients?","options":["A. Children should be treated with scaled-down adult protocols","B. Children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size","C. Pediatric care is identical to adult care below a certain weight threshold","D. Only infants require a different assessment approach"],"correct":1,"rationale":"PEPP's foundational premise is that children are not small adults — differences span anatomy, physiology, development, and psychosocial needs, requiring a distinct approach at every stage of care.","difficulty":"Easy"},{"id":"c01_q02","question":"Where is the narrowest point of a young child's airway located?","options":["A. At the vocal cords, same as adults","B. Subglottic, below the vocal cords","C. At the nostrils","D. At the epiglottis only"],"correct":1,"rationale":"Unlike adults, whose airway narrows at the vocal cords, a young child's airway is narrowest below the cords (subglottic), an important anatomic difference for airway management.","difficulty":"Medium"},{"id":"c01_q03","question":"Why do children desaturate faster than adults when breathing is compromised?","options":["A. They have larger oxygen reserves","B. Higher metabolic rate/oxygen consumption combined with smaller functional residual capacity","C. They breathe more slowly than adults","D. Their chest walls are stiffer than adults'"],"correct":1,"rationale":"Children consume more oxygen per kilogram than adults but have less reserve capacity in the lungs, so oxygenation drops faster when ventilation is impaired.","difficulty":"Medium"},{"id":"c01_q04","question":"What is the leading pathway to cardiac arrest in children, distinct from adults?","options":["A. Primary cardiac dysrhythmia","B. Respiratory problems","C. Toxic ingestion","D. Congenital heart disease in all cases"],"correct":1,"rationale":"Unlike adults where primary cardiac events predominate, pediatric arrest is most often the end result of progressive respiratory failure or shock.","difficulty":"Easy"},{"id":"c01_q05","question":"Why is blood pressure considered a late and unreliable early sign of shock in children?","options":["A. Children cannot mount a compensatory response","B. Children compensate well via tachycardia and vasoconstriction, maintaining normal BP until significant volume is lost","C. Blood pressure is always elevated in pediatric shock","D. Children's blood pressure cannot be measured accurately"],"correct":1,"rationale":"Robust compensatory mechanisms keep blood pressure normal-appearing until a substantial percentage of circulating volume is lost, making BP a poor early screening tool in children.","difficulty":"Medium"},{"id":"c01_q06","question":"What happens once a child's shock compensation fails?","options":["A. Gradual, well-tolerated decline","B. Rapid decompensation with little warning","C. Spontaneous recovery","D. No change in clinical status"],"correct":1,"rationale":"Because compensation in children is so effective until it isn't, decompensation — once it begins — tends to occur rapidly, giving little advance warning.","difficulty":"Medium"},{"id":"c01_q07","question":"What is the best approach to assessing a frightened toddler?","options":["A. Separate the child from caregivers immediately for an accurate exam","B. Keep the caregiver close and demonstrate equipment on a doll or the caregiver first","C. Use complex medical terminology to build trust","D. Approach with unfamiliar equipment first to desensitize the child"],"correct":1,"rationale":"Toddlers fear separation and unfamiliar equipment; keeping caregivers close and demonstrating equipment first reduces distress and improves cooperation and assessment accuracy.","difficulty":"Easy"},{"id":"c01_q08","question":"What is the best approach to interviewing an adolescent patient?","options":["A. Always keep a parent present for every question","B. Provide privacy, respect, and honesty, considering some interview time apart from caregivers","C. Speak only to the caregiver, not the patient","D. Use the same approach as with a toddler"],"correct":1,"rationale":"Adolescents value privacy, respect, and direct honesty, and may disclose more accurately when interviewed partly apart from caregivers.","difficulty":"Easy"},{"id":"c01_q09","question":"Why is a single 'normal vital signs' reference not useful in pediatrics?","options":["A. Vital signs don't matter in children","B. Normal heart rate, respiratory rate, and blood pressure vary substantially across pediatric age bands","C. Pediatric vital signs cannot be measured in the field","D. All children have identical vital signs regardless of age"],"correct":1,"rationale":"Because normal ranges shift significantly from neonate through adolescent, every vital sign must be compared against an age-appropriate reference range.","difficulty":"Easy"},{"id":"c01_q10","question":"What matters more than a single isolated vital sign reading in pediatric assessment?","options":["A. The exact numeric value alone","B. Trends over time and the overall clinical picture (e.g., the Pediatric Assessment Triangle)","C. Only the respiratory rate","D. The child's stated pain level alone"],"correct":1,"rationale":"A single vital sign can be misleading in isolation; trends and the broader clinical gestalt provide more reliable information about the child's true status.","difficulty":"Medium"},{"id":"c01_q11","question":"Why does a modest-seeming blood loss matter more in a child than in an adult?","options":["A. Children have larger total blood volumes","B. A child's absolute circulating blood volume is small, so the same loss is a larger percentage of total volume","C. Children's blood clots more slowly","D. This is not actually true — losses are equivalent"],"correct":1,"rationale":"Because total circulating volume is smaller in children, an amount of blood loss that would be minor in an adult can represent a much larger fraction of a child's total volume.","difficulty":"Medium"},{"id":"c01_q12","question":"How does the pediatric larynx position differ anatomically from an adult's?","options":["A. More posterior and lower","B. More anterior and cephalad (higher)","C. Identical position","D. Absent in infants"],"correct":1,"rationale":"The pediatric larynx sits more anterior and cephalad than the adult larynx, an important consideration for airway positioning and visualization.","difficulty":"Medium"},{"id":"c01_q13","question":"Why are infants at particular risk of fatigue during increased work of breathing?","options":["A. They have highly rigid chest walls","B. They are diaphragmatic breathers with a compliant chest wall, generating less effective negative pressure and fatiguing faster","C. Infants never show signs of respiratory distress","D. Infant lungs have unusually large reserve capacity"],"correct":1,"rationale":"The compliant infant chest wall and diaphragm-dependent breathing generate less effective ventilatory force, so infants tire more quickly when working hard to breathe.","difficulty":"Hard"},{"id":"c01_q14","question":"A provider uses an adult mental model unmodified when assessing an infant's airway. What is the risk?","options":["A. No risk — pediatric and adult airways are identical","B. Missing anatomic differences (large tongue, anterior/cephalad larynx, subglottic narrowing) that change positioning and equipment needs","C. Improved outcomes from consistency","D. The risk only applies to children over age 10"],"correct":1,"rationale":"Anatomic differences unique to the pediatric airway change how it should be assessed and managed; applying an unmodified adult model risks missing or mismanaging obstruction.","difficulty":"Hard"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"What are the three legs of the Pediatric Assessment Triangle?","options":["A. Airway, Breathing, Circulation","B. Appearance, Work of Breathing, Circulation to Skin","C. History, Exam, Vital Signs","D. Tone, Color, Cry"],"correct":1,"rationale":"The PAT's three legs are Appearance, Work of Breathing, and Circulation to Skin — assessed together from across the room before any hands-on contact.","difficulty":"Easy"},{"id":"c02_q02","question":"What does the TICLS mnemonic help assess?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance","D. Vital signs"],"correct":2,"rationale":"TICLS (Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry) breaks down the Appearance leg of the PAT into observable components.","difficulty":"Easy"},{"id":"c02_q03","question":"A child is limp, will not make eye contact, and is inconsolable, but breathing appears effortless and skin color is normal. What does this pattern suggest?","options":["A. A respiratory problem","B. A primarily CNS/metabolic problem","C. A shock/circulatory problem","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance alone, with normal Work of Breathing and Circulation, points toward a CNS/metabolic category rather than a respiratory or circulatory problem.","difficulty":"Medium"},{"id":"c02_q04","question":"A child has abnormal Appearance (lethargic) AND visible retractions with nasal flaring, but normal skin color. What is the likely category?","options":["A. CNS/metabolic problem","B. Respiratory problem","C. Shock","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance combined with abnormal Work of Breathing (retractions, flaring), with normal circulation, points to a respiratory category.","difficulty":"Medium"},{"id":"c02_q05","question":"A child is lethargic and has mottled, cool skin, but breathing appears unlabored with no retractions. What is the likely category?","options":["A. Respiratory problem","B. Shock/circulatory problem","C. Normal finding","D. Isolated CNS problem only"],"correct":1,"rationale":"Abnormal Appearance plus abnormal Circulation to Skin, with normal Work of Breathing, suggests a shock/circulatory category.","difficulty":"Medium"},{"id":"c02_q06","question":"A child shows abnormal findings across ALL three PAT legs. What does this represent?","options":["A. A mild, self-limited illness","B. Cardiopulmonary failure — the highest-urgency category","C. Normal variation","D. An isolated skin condition"],"correct":1,"rationale":"Abnormality across all three legs indicates a severe, multi-system problem — cardiopulmonary failure — requiring the most urgent response.","difficulty":"Medium"},{"id":"c02_q07","question":"Is the PAT performed with a stethoscope or blood pressure cuff?","options":["A. Yes, both are required","B. No — it is entirely hands-off, visual and auditory, from across the room","C. Only a stethoscope is used","D. Only a BP cuff is used"],"correct":1,"rationale":"The PAT is deliberately hands-off, performed by observation and listening from a distance before any equipment or touching begins.","difficulty":"Easy"},{"id":"c02_q08","question":"A child looks well on the PAT. What should the provider do next?","options":["A. Skip the primary assessment since the PAT was reassuring","B. Proceed to a full hands-on primary assessment at a calmer pace","C. Discharge the patient immediately","D. Only check vital signs, skip any exam"],"correct":1,"rationale":"The PAT never replaces the hands-on primary assessment — a reassuring PAT sets a calmer pace, but the full ABCDE assessment still follows.","difficulty":"Easy"},{"id":"c02_q09","question":"Why is Work of Breathing considered an 'early window' into respiratory status?","options":["A. It only becomes abnormal after the child has already desaturated","B. Increased effort reflects compensation and can appear before oxygen saturation falls","C. It has no relationship to oxygenation","D. It is only useful in adults"],"correct":1,"rationale":"Increased work of breathing is a compensatory response that often precedes a measurable drop in SpO2, making it an early indicator of respiratory compromise.","difficulty":"Medium"},{"id":"c02_q10","question":"Which finding is part of the Circulation to Skin leg of the PAT?","options":["A. Retractions","B. Nasal flaring","C. Mottling","D. Stridor"],"correct":2,"rationale":"Mottling is a skin-color finding assessed under Circulation to Skin; retractions, flaring, and stridor belong to the Work of Breathing leg.","difficulty":"Easy"},{"id":"c02_q11","question":"Why is Appearance considered the most sensitive PAT leg?","options":["A. It is the easiest to measure with equipment","B. It reflects the adequacy of oxygenation, ventilation, brain perfusion, and CNS function all at once","C. It is only relevant in trauma","D. It replaces the need for the other two legs"],"correct":1,"rationale":"Appearance integrates multiple physiologic systems, making it a highly sensitive early indicator — an abnormal Appearance is a red flag even if the other two legs look normal.","difficulty":"Medium"},{"id":"c02_q12","question":"What is meant by assessing the PAT 'from the doorway'?","options":["A. Only assessing patients who are near an actual doorway","B. The PAT is completed within the first seconds of encountering the child, before approaching or touching them","C. The PAT requires the child to be standing in a doorway","D. This phrase has no specific meaning in PEPP"],"correct":1,"rationale":"The 'from the doorway' framing captures how quickly and unobtrusively the PAT is performed — a rapid visual/auditory read taken immediately upon encountering the child.","difficulty":"Medium"},{"id":"c02_q13","question":"A muffled, weak cry in an infant is a finding under which PAT leg?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance (Speech/Cry component of TICLS)","D. None of the legs"],"correct":2,"rationale":"Speech/Cry is one of the five TICLS components under the Appearance leg; a weak or muffled cry is an abnormal Appearance finding.","difficulty":"Medium"},{"id":"c02_q14","question":"Why does the PAT drive 'the pace of everything that follows' rather than the content of care?","options":["A. It determines drug doses directly","B. It sets the general impression and urgency level, shaping how quickly the primary assessment proceeds and whether interventions happen simultaneously","C. It has no influence on subsequent care","D. It replaces vital sign measurement entirely"],"correct":1,"rationale":"The PAT's purpose is to establish urgency and likely category quickly, which shapes the speed and sequencing of the ensuing primary assessment and interventions — not to dictate specific treatments by itself.","difficulty":"Hard"},{"id":"c02_q15","question":"Which combination of PAT findings would most strongly suggest the HIGHEST acuity requiring the most urgent response?","options":["A. Normal Appearance, normal Work of Breathing, normal Circulation","B. Abnormal Appearance, Work of Breathing, AND Circulation to Skin all together","C. Mild nasal flaring only, otherwise normal","D. Slightly pale skin with normal Appearance and breathing"],"correct":1,"rationale":"Abnormalities across all three PAT legs together represent the cardiopulmonary failure category, the highest-urgency PAT pattern.","difficulty":"Medium"},{"id":"c02_q16","question":"How should skin color findings under Circulation to Skin be interpreted?","options":["A. Against a universal standard regardless of the individual child","B. Against the child's own baseline skin tone, in adequate lighting","C. Only cyanosis matters; pallor and mottling are irrelevant","D. Skin color cannot be reliably assessed in the field"],"correct":1,"rationale":"Skin findings are compared to the individual child's baseline tone under good lighting, since a fixed universal standard would not account for normal variation between children.","difficulty":"Medium"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The 'Reassuring' Blood Pressure","presentation":"A 6-year-old boy fell from a bicycle and has an obviously deformed thigh with visible bruising. He is pale and anxious. His blood pressure reads within the normal range for his age, but his heart rate is elevated.","vitals":{"hr":"128 bpm (elevated for age)","bp":"94/62 mmHg (age-normal)","rr":"26 bpm","skin":"Pale, cool"},"question":"How should the 'normal' blood pressure be interpreted?","options":["A: It rules out significant blood loss or shock.","B: It should NOT be reassuring — children compensate well and maintain blood pressure until a large percentage of volume is lost; the tachycardia and pale, cool skin suggest early compensated shock.","C: It means his heart rate reading is inaccurate.","D: It indicates he is anxious only, with no physiologic concern."],"correct":1,"explanation":"Blood pressure is a late sign in pediatric shock. This child's tachycardia and pale, cool skin — despite a numerically normal blood pressure for his age — suggest early compensated shock from his femur fracture, and should prompt close monitoring and volume assessment rather than reassurance from the BP alone.","clinicalPearl":"In children, don't let a 'normal' blood pressure talk you out of what the rest of the exam is telling you."},{"id":"c01_s02","title":"The Screaming Toddler","presentation":"A 2-year-old girl with a fever is screaming and clinging to her mother, arching away whenever you approach with your stethoscope.","vitals":{"temp":"102.6 F","hr":"Elevated, difficult to auscultate due to crying","loc":"Alert, distressed"},"question":"What is the best approach to complete a useful assessment?","options":["A: Separate her from her mother to get a controlled exam.","B: Keep her on her mother's lap, demonstrate the stethoscope on the mother first, and assess from a distance (appearance, work of breathing, color) before hands-on exam.","C: Restrain her firmly to listen to her lungs.","D: Skip the exam since she won't cooperate."],"correct":1,"explanation":"Toddlers fear separation and unfamiliar equipment. Keeping her with her caregiver, demonstrating tools first, and starting with an across-the-room observational assessment (matching the developmental-stage approach in this chapter) both calms the child and yields more reliable findings than forcing a hands-on exam immediately.","clinicalPearl":"With toddlers, the best exam often starts before you ever touch them — watch first, demonstrate second, touch last."},{"id":"c01_s03","title":"Small Loss, Big Percentage","presentation":"A 9 kg infant has been vomiting and having diarrhea for 18 hours. The caregiver estimates about 300 mL of combined fluid loss, which they describe as 'not that much.'","vitals":{"weight":"9 kg","estimated loss":"~300 mL","hr":"elevated","skin":"dry mucous membranes, decreased tears"},"question":"Why is this fluid loss more significant than the caregiver's framing suggests?","options":["A: 300 mL is trivial regardless of the infant's size.","B: A child's absolute circulating blood/fluid volume is small, so 300 mL represents a much larger percentage of this infant's total volume than the same amount would in an adult.","C: Fluid loss is never clinically significant in infants.","D: This amount is only concerning if the infant is over 1 year old."],"correct":1,"explanation":"Because total circulating volume scales with body size, an absolute loss that sounds modest can represent a dangerously large percentage of a small infant's total volume — one of the core anatomic/physiologic reasons children are not small adults when estimating losses.","clinicalPearl":"Always translate an absolute fluid loss into a percentage of THIS child's estimated total volume — the same number means very different things at different weights."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"From the Doorway","presentation":"You enter a home and see a 3-year-old boy sitting quietly in his mother's lap. He is looking around the room, tracking your movement, and reaches for a toy his sister offers. His breathing looks effortless and his skin has a normal pink color.","vitals":{"appearance":"Alert, interactive, tracks movement","wob":"No retractions, no abnormal sounds","circulation":"Normal color"},"question":"What does this PAT pattern suggest, and what should you do next?","options":["A: All three legs normal — this is a reassuring PAT; proceed to a full hands-on primary assessment at a normal pace.","B: This is enough information to clear the child without further assessment.","C: You should immediately begin aggressive interventions given the visit itself is concerning.","D: Skip vital signs since the child looks fine."],"correct":0,"explanation":"All three PAT legs (Appearance, Work of Breathing, Circulation to Skin) appear normal, giving a reassuring general impression. This sets a calmer pace for the encounter, but a full hands-on primary assessment (ABCDE) still follows — the PAT never substitutes for it.","clinicalPearl":"A reassuring PAT buys you time and calm, not an exemption from the primary assessment."},{"id":"c02_s02","title":"Two Legs Down","presentation":"A 5-year-old girl with a history of asthma is sitting in the tripod position, with visible subcostal and intercostal retractions and audible wheezing. She is alert, tracking you, and answering questions appropriately. Her skin color looks normal.","vitals":{"appearance":"Alert, interactive (normal)","wob":"Tripod position, retractions, wheeze (abnormal)","circulation":"Normal color"},"question":"Which PAT category does this pattern suggest, and how urgent is it?","options":["A: CNS/metabolic problem — treat as a neurologic emergency.","B: Respiratory problem (abnormal Work of Breathing with normal Appearance and Circulation) — urgent but with intact compensation reflected by her normal Appearance.","C: Cardiopulmonary failure — the most urgent category.","D: A normal, reassuring PAT."],"correct":1,"explanation":"Only the Work of Breathing leg is abnormal here; her Appearance remaining normal suggests she is still compensating well despite significant respiratory effort. This points to a respiratory category requiring urgent treatment (e.g., bronchodilator therapy) rather than the higher-urgency multi-leg patterns.","clinicalPearl":"A normal Appearance despite visible respiratory effort is a relatively reassuring sign — it means the compensation is still working."},{"id":"c02_s03","title":"All Three Legs Abnormal","presentation":"A 7-month-old infant is limp and unresponsive to his mother's voice, with slow, irregular, gasping-appearing breaths and dusky, mottled skin.","vitals":{"appearance":"Limp, unresponsive (abnormal)","wob":"Irregular, gasping breaths (abnormal)","circulation":"Dusky, mottled (abnormal)"},"question":"What does this pattern indicate, and what is the priority?","options":["A: A mild, self-limited illness requiring routine transport.","B: Cardiopulmonary failure — abnormal findings across all three PAT legs — the highest-acuity pattern, requiring the most immediate, aggressive response.","C: A purely circulatory problem with no respiratory component.","D: This pattern is not clinically meaningful without vital signs first."],"correct":1,"explanation":"Abnormal findings across all three PAT legs (Appearance, Work of Breathing, Circulation to Skin) together indicate cardiopulmonary failure, the most severe PAT pattern, demanding the most urgent, simultaneous life-saving response — this recognition happens before any vital sign is even obtained.","clinicalPearl":"All three legs abnormal is the PAT's loudest alarm — it means go now, with everything, before you've measured a single vital sign."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Applying Anatomic/Developmental Context to Any Pediatric Encounter","description":"The foundational sequence for interpreting any pediatric finding in age- and development-appropriate context.","steps":["Identify the child's age band before interpreting any vital sign or exam finding.","Recall the anatomic differences relevant to the presenting complaint (airway: narrow/anterior/subglottic; breathing: high demand/low reserve; circulation: small volume/strong compensation).","Compare vital signs to the age-appropriate normal range, not an adult or generic pediatric reference.","Adapt your communication and exam approach to the child's developmental stage to maximize cooperation and accuracy.","Weigh all findings together (overall gestalt) rather than relying on any single number, especially blood pressure, which is a late sign in pediatric shock."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"Performing the Pediatric Assessment Triangle","description":"The hands-off, from-the-doorway assessment performed within the first seconds of any pediatric encounter.","steps":["Approach the child without touching; observe from across the room.","Assess Appearance using TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Assess Work of Breathing: listen for abnormal sounds (stridor, grunting, wheeze, muffled voice); look for abnormal positioning, retractions, nasal flaring, head bobbing.","Assess Circulation to Skin: look for pallor, mottling, or cyanosis compared to the child's baseline, in adequate lighting.","Combine all three legs into a pattern to identify the likely physiologic category and urgency.","Proceed immediately to the full hands-on primary assessment (ABCDE), paced according to the PAT's urgency level."]},{"id":"c02_alg02","title":"PAT Pattern-to-Category Recognition","description":"Translating the combination of abnormal PAT legs into a likely physiologic category.","steps":["Abnormal Appearance only → likely CNS/metabolic problem.","Abnormal Appearance + Work of Breathing → likely respiratory problem.","Abnormal Appearance + Circulation to Skin → likely shock/circulatory problem.","Abnormal Appearance + Work of Breathing + Circulation to Skin → cardiopulmonary failure (highest urgency).","All three legs normal → reassuring general impression; proceed to primary assessment at a routine pace."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Age-Banded Normal Pediatric Vital Signs","headers":["Age Group","Heart Rate (bpm)","Respiratory Rate (breaths/min)","Systolic BP (mmHg)","Hypotension Threshold (SBP)"],"rows":[["Neonate (0–28 days)","100–160","30–60","60–80","< 60 mmHg"],["Infant (1–12 months)","100–160","24–40","70–100","< 70 mmHg"],["Toddler (1–3 years)","90–150","20–30","80–100","< 74 mmHg (70 + 2×2)"],["Preschool (4–5 years)","80–140","20–28","85–110","< 78–80 mmHg (70 + 2×[4–5])"],["School-age (6–12 years)","70–120","18–24","90–120","< 82–94 mmHg (70 + 2×[6–12])"],["Adolescent (13–18 years)","60–100","12–20","100–130","< 90 mmHg (adult threshold)"]]},{"id":"c01_t02","title":"Developmental Stage & Communication Approach","headers":["Stage","Typical Fears/Concerns","Assessment Approach"],"rows":[["Infant (0–12 mo)","Separation from caregiver, hunger, discomfort","Assess largely by observation; keep with caregiver; minimize handling"],["Toddler (1–3 yr)","Separation, strangers, unfamiliar equipment","Keep caregiver close; demonstrate equipment on doll/caregiver first; toe-to-head exam order"],["Preschool (4–5 yr)","Bodily injury, the unknown, magical thinking","Simple honest explanations; allow choices where possible; involve caregiver"],["School-age (6–12 yr)","Loss of control, being different from peers","Direct honest explanation; involve child in decisions; respect modesty"],["Adolescent (13–18 yr)","Privacy, body image, independence","Privacy and respect; consider interviewing partly apart from caregivers; honesty about findings"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"Pediatric Assessment Triangle — Legs and Findings","headers":["Leg","Mnemonic/Focus","Normal","Abnormal"],"rows":[["Appearance","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry","Alert, interactive, consolable, strong cry/speech","Limp, uninterested, inconsolable, weak/absent cry"],["Work of Breathing","Sounds, position, retractions, flaring, head bobbing","Quiet, comfortable position, no retractions","Stridor/grunting/wheeze, tripod position, retractions, flaring, head bobbing"],["Circulation to Skin","Color compared to baseline","Pink, normal color for the child","Pallor, mottling, cyanosis"]]},{"id":"c02_t02","title":"PAT Pattern → Likely Category","headers":["Abnormal Leg(s)","Likely Category","Urgency"],"rows":[["Appearance only","CNS/metabolic problem","Elevated"],["Appearance + Work of Breathing","Respiratory problem","Urgent"],["Appearance + Circulation to Skin","Shock/circulatory problem","Urgent"],["Appearance + Work of Breathing + Circulation to Skin","Cardiopulmonary failure","Highest — immediate action"],["None (all normal)","Reassuring general impression","Routine pace"]]}]}}};
